 1→package auth
 2→
 3→import (
 4→	"context"
 5→	"strings"
 6→
 7→	"github.com/ALRubinger/aileron/core/store"
 8→)
 9→
10→// StoreEnforcer implements the Enforcer interface using the enterprise store.
11→type StoreEnforcer struct {
12→	enterprises store.EnterpriseStore
13→}
14→
15→// NewStoreEnforcer creates an enforcer backed by the enterprise store.
16→func NewStoreEnforcer(enterprises store.EnterpriseStore) *StoreEnforcer {
17→	return &StoreEnforcer{enterprises: enterprises}
18→}
19→
20→func (e *StoreEnforcer) IsProviderAllowed(ctx context.Context, enterpriseID string, provider string) (bool, error) {
21→	ent, err := e.enterprises.Get(ctx, enterpriseID)
22→	if err != nil {
23→		return false, err
24→	}
25→	// No restrictions configured means all providers are allowed.
26→	if len(ent.AllowedAuthProviders) == 0 {
27→		return true, nil
28→	}
29→	for _, p := range ent.AllowedAuthProviders {
30→		if p == provider {
31→			return true, nil
32→		}
33→	}
34→	return false, nil
35→}
36→
37→func (e *StoreEnforcer) IsSSORequired(ctx context.Context, enterpriseID string) (bool, error) {
38→	ent, err := e.enterprises.Get(ctx, enterpriseID)
39→	if err != nil {
40→		return false, err
41→	}
42→	return ent.SSORequired, nil
43→}
44→
45→func (e *StoreEnforcer) IsEmailDomainAllowed(ctx context.Context, enterpriseID string, email string) (bool, error) {
46→	ent, err := e.enterprises.Get(ctx, enterpriseID)
47→	if err != nil {
48→		return false, err
49→	}
50→	// No domain restrictions means all domains are allowed.
51→	if len(ent.AllowedEmailDomains) == 0 {
52→		return true, nil
53→	}
54→	parts := strings.SplitN(email, "@", 2)
55→	if len(parts) != 2 {
56→		return false, nil
57→	}
58→	domain := strings.ToLower(parts[1])
59→	for _, d := range ent.AllowedEmailDomains {
60→		if strings.ToLower(d) == domain {
61→			return true, nil
62→		}
63→	}
64→	return false, nil
65→}
