 13→// GetCurrentEnterprise and GetCurrentUser are generated ServerInterface
 14→// methods for the Enterprises and Users tags. Auth endpoints (Auth tag)
 15→// are excluded from code generation and handled by core/auth.Handler.
 16→
 17→func (s *apiServer) GetCurrentEnterprise(w http.ResponseWriter, r *http.Request) {
 18→	claims := auth.ClaimsFromContext(r.Context())
 19→	if claims == nil {
 20→		http.Error(w, `{"error":"not authenticated"}`, http.StatusUnauthorized)
 21→		return
 22→	}
 23→
 24→	if s.enterprises == nil {
 25→		http.Error(w, `{"error":"auth not enabled"}`, http.StatusNotImplemented)
 26→		return
 27→	}
 28→
 29→	ent, err := s.enterprises.Get(r.Context(), claims.EnterpriseID)
 30→	if err != nil {
 31→		http.Error(w, `{"error":"enterprise not found"}`, http.StatusNotFound)
 32→		return
 33→	}
 34→	writeJSON(w, http.StatusOK, enterpriseToAPI(ent))
 35→}
