  1→import { PUBLIC_API_BASE } from '$env/static/public';
  2→
  3→const TOKEN_KEY = 'aileron_access_token';
  4→const REFRESH_KEY = 'aileron_refresh_token';
  5→
  6→/** Reactive auth state using Svelte 5 runes via module-level $state. */
  7→let _token = $state<string | null>(null);
  8→let _user = $state<AuthUser | null>(null);
  9→
 10→export interface AuthUser {
 11→	id: string;
 12→	email: string;
 13→	display_name: string;
 14→	avatar_url?: string;
 15→	role: string;
 16→	enterprise_id: string;
 17→}
 18→
 19→/** Initialize auth state from localStorage (call once on app mount). */
 20→export function initAuth() {
 21→	if (typeof window === 'undefined') return;
 22→	_token = localStorage.getItem(TOKEN_KEY);
 23→	if (_token) {
 24→		fetchCurrentUser().catch(() => clearAuth());
 25→	}
 26→}
 27→
 28→/** Returns the current access token, or null. */
 29→export function getToken(): string | null {
 30→	return _token;
 31→}
 32→
 33→/** Returns the current user, or null. */
 34→export function getUser(): AuthUser | null {
 35→	return _user;
 36→}
 37→
 38→/** Returns true if the user is authenticated. */
 39→export function isAuthenticated(): boolean {
 40→	return _token !== null;
 41→}
 42→
 43→/** Store tokens after login/signup and fetch user profile. */
 44→export async function setAuth(accessToken: string, refreshToken?: string) {
 45→	_token = accessToken;
 46→	localStorage.setItem(TOKEN_KEY, accessToken);
 47→	if (refreshToken) {
 48→		localStorage.setItem(REFRESH_KEY, refreshToken);
 49→	}
 50→	await fetchCurrentUser();
 51→}
 52→
 53→/** Clear auth state (logout). */
 54→export function clearAuth() {
 55→	_token = null;
 56→	_user = null;
 57→	localStorage.removeItem(TOKEN_KEY);
 58→	localStorage.removeItem(REFRESH_KEY);
 59→}
 60→
 61→/** Attempt to refresh the access token using the stored refresh token. */
 62→export async function refreshAuth(): Promise<boolean> {
 63→	const refreshToken = localStorage.getItem(REFRESH_KEY);
 64→	if (!refreshToken) return false;
 65→
 66→	try {
 67→		const res = await fetch(`${PUBLIC_API_BASE}/auth/refresh`, {
 68→			method: 'POST',
 69→			credentials: 'include',
 70→			headers: { 'Content-Type': 'application/json' },
 71→			body: JSON.stringify({ refresh_token: refreshToken })
 72→		});
 73→		if (!res.ok) {
 74→			clearAuth();
 75→			return false;
 76→		}
 77→		const data = await res.json();
 78→		_token = data.access_token;
 79→		localStorage.setItem(TOKEN_KEY, data.access_token);
 80→		return true;
 81→	} catch {
 82→		clearAuth();
 83→		return false;
 84→	}
 85→}
 86→
 87→/** Re-fetch the current user profile and update reactive state. */
 88→export async function refreshUser() {
 89→	return fetchCurrentUser();
 90→}
 91→
 92→/** Fetch the current user profile from /v1/users/me. */
 93→async function fetchCurrentUser() {
 94→	const headers: Record<string, string> = {};
 95→	// Use Bearer token for password-based auth; use cookies for OAuth flow.
 96→	if (_token && _token !== 'cookie-auth') {
 97→		headers['Authorization'] = `Bearer ${_token}`;
 98→	}
 99→	const res = await fetch(`${PUBLIC_API_BASE}/v1/users/me`, {
100→		headers,
101→		credentials: 'include'
102→	});
103→	if (!res.ok) throw new Error('Failed to fetch user');
104→	_user = await res.json();
105→}
106→
107→// --- Auth API calls (signup, login, verify) ---
108→
109→export async function signup(email: string, password: string, displayName?: string) {
110→	const res = await fetch(`${PUBLIC_API_BASE}/auth/signup`, {
111→		method: 'POST',
112→		headers: { 'Content-Type': 'application/json' },
113→		body: JSON.stringify({ email, password, display_name: displayName })
114→	});
115→	if (!res.ok) {
116→		const err = await res.json().catch(() => ({ error: res.statusText }));
117→		throw new Error(err.error || res.statusText);
118→	}
119→	return res.json();
120→}
121→
122→export async function verifyEmail(email: string, code: string) {
123→	const res = await fetch(`${PUBLIC_API_BASE}/auth/verify-email`, {
124→		method: 'POST',
125→		headers: { 'Content-Type': 'application/json' },
126→		body: JSON.stringify({ email, code })
127→	});
128→	if (!res.ok) {
129→		const err = await res.json().catch(() => ({ error: res.statusText }));
130→		throw new Error(err.error || res.statusText);
131→	}
132→	return res.json();
133→}
134→
135→export async function emailLogin(email: string, password: string) {
136→	const res = await fetch(`${PUBLIC_API_BASE}/auth/login`, {
137→		method: 'POST',
138→		headers: { 'Content-Type': 'application/json' },
139→		body: JSON.stringify({ email, password })
140→	});
141→	if (!res.ok) {
142→		const err = await res.json().catch(() => ({ error: res.statusText }));
143→		throw new Error(err.error || res.statusText);
144→	}
145→	return res.json();
146→}
147→
148→export async function logout() {
149→	try {
150→		await fetch(`${PUBLIC_API_BASE}/auth/logout`, {
151→			method: 'POST',
152→			headers: _token ? { Authorization: `Bearer ${_token}` } : {}
153→		});
154→	} catch {
155→		// Best-effort server-side logout.
156→	}
157→	clearAuth();
158→}
