150→func userToAPI(u model.User) api.User {
151→	out := api.User{
152→		Id:              u.ID,
153→		EnterpriseId:    u.EnterpriseID,
154→		Email:           openapi_types.Email(u.Email),
155→		DisplayName:     u.DisplayName,
156→		Role:            api.UserRole(u.Role),
157→		Status:          api.UserStatus(u.Status),
158→		AuthProvider:    u.AuthProvider,
159→		LastLoginAt:     u.LastLoginAt,
160→		CreatedAt:       u.CreatedAt,
161→		UpdatedAt:       u.UpdatedAt,
162→	}
163→	if u.AvatarURL != "" {
164→		out.AvatarUrl = &u.AvatarURL
165→	}
166→	return out
167→}
168→
169→func enterpriseToAPI(e model.Enterprise) api.Enterprise {
170→	out := api.Enterprise{
171→		Id:           e.ID,
172→		Name:         e.Name,
173→		Slug:         e.Slug,
174→		Plan:         api.EnterprisePlan(e.Plan),
175→		BillingEmail: openapi_types.Email(e.BillingEmail),
176→		CreatedAt:    e.CreatedAt,
177→		UpdatedAt:    e.UpdatedAt,
178→	}
179→	if e.Personal {
180→		out.Personal = &e.Personal
181→	}
182→	if e.SSORequired {
183→		out.SsoRequired = &e.SSORequired
184→	}
185→	if len(e.AllowedAuthProviders) > 0 {
186→		out.AllowedAuthProviders = &e.AllowedAuthProviders
187→	}
188→	if len(e.AllowedEmailDomains) > 0 {
189→		out.AllowedEmailDomains = &e.AllowedEmailDomains
190→	}
191→	return out
192→}
