// Package auth defines the SPI for authentication providers.
//
// An AuthProvider bridges the control plane to an external identity provider —
// Google OAuth, Okta OIDC, a generic SAML 2.0 IdP, etc. When a user initiates
// login, the control plane selects the appropriate provider and delegates the
// authentication flow.
//
// Each provider implementation handles one external identity system. The SPI
// is intentionally narrow: providers generate an authorization URL and exchange
// a callback for an identity. Session management and JWT issuance happen in the
// control plane after the provider returns.
//
// The Enforcer interface checks enterprise-level SSO policies — whether a
// provider is allowed, whether SSO is required, and whether an email domain
// is permitted. These checks run after the provider returns an identity but
// before the user is granted a session.
package auth

import "context"

// AuthProvider authenticates users via an external identity provider.
type AuthProvider interface {
	// Provider returns the provider identifier (e.g. "google", "okta").
	Provider() string

	// AuthorizationURL returns the URL to redirect the user to for login.
	// The state parameter is an opaque CSRF token that must be echoed back
	// in the callback. redirectURL is the callback URL the provider should
	// redirect to after authentication.
	AuthorizationURL(ctx context.Context, state, redirectURL string) (string, error)

	// HandleCallback exchanges the authorization code from the IdP callback
	// for a resolved user identity.
	HandleCallback(ctx context.Context, req CallbackRequest) (*Identity, error)
}

// CallbackRequest contains the data from the OAuth/OIDC callback.
type CallbackRequest struct {
	Code        string
	State       string
	RedirectURL string // must match the redirectURL used in AuthorizationURL
}

// Identity is the authenticated user identity returned by a provider.
type Identity struct {
	// Subject is the provider-specific unique user identifier.
	Subject     string
	Email       string
	DisplayName string
	AvatarURL   string
	Provider    string
	// RawClaims carries the full set of claims from the IdP for extensibility.
	RawClaims map[string]any
}

// Enforcer checks enterprise-level SSO policies.
type Enforcer interface {
	// IsProviderAllowed reports whether the given auth provider is permitted
	// for the enterprise. Returns true if the enterprise has no provider
	// restrictions configured.
	IsProviderAllowed(ctx context.Context, enterpriseID string, provider string) (bool, error)

	// IsSSORequired reports whether the enterprise requires all users to
	// authenticate via a configured SSO provider.
	IsSSORequired(ctx context.Context, enterpriseID string) (bool, error)

	// IsEmailDomainAllowed reports whether the user's email domain is
	// permitted for the enterprise. Returns true if the enterprise has no
	// domain restrictions configured.
	IsEmailDomainAllowed(ctx context.Context, enterpriseID string, email string) (bool, error)
}

// Registry holds registered auth providers and resolves the correct one
// for a given provider name. It is safe for concurrent use.
type Registry struct {
	providers map[string]AuthProvider
}

// NewRegistry returns an empty auth provider registry.
func NewRegistry() *Registry {
	return &Registry{providers: make(map[string]AuthProvider)}
}

// Register adds an auth provider to the registry.
func (r *Registry) Register(p AuthProvider) {
	r.providers[p.Provider()] = p
}

// Get returns the provider for the given name, or nil if not registered.
func (r *Registry) Get(name string) (AuthProvider, bool) {
	p, ok := r.providers[name]
	return p, ok
}

package config

import (
	"fmt"
	"os"
	"time"
)

// AuthConfig holds authentication configuration, loaded from environment
// variables. Secrets (client secrets, signing keys) must not be stored in
// the YAML config file.
type AuthConfig struct {
	// DatabaseURL is the PostgreSQL connection string.
	// Env: AILERON_DATABASE_URL
	DatabaseURL string

	// JWTSigningKey is the HMAC key for signing access tokens.
	// Env: AILERON_JWT_SIGNING_KEY
	JWTSigningKey string

	// JWTIssuer is the "iss" claim in issued tokens.
	// Env: AILERON_JWT_ISSUER (default: "aileron")
	JWTIssuer string

	// AccessTokenTTL is the lifetime of access tokens.
	// Env: AILERON_ACCESS_TOKEN_TTL (default: "15m")
	AccessTokenTTL time.Duration

	// RefreshTokenTTL is the lifetime of refresh tokens.
	// Env: AILERON_REFRESH_TOKEN_TTL (default: "168h" = 7 days)
	RefreshTokenTTL time.Duration

	// UIRedirectURL is where users are sent after successful auth.
	// Env: AILERON_UI_REDIRECT_URL (default: "/")
	UIRedirectURL string

	// AutoVerifyEmail skips email verification on signup, activating
	// accounts immediately. For development and CI only.
	// Env: AILERON_AUTO_VERIFY_EMAIL
	AutoVerifyEmail bool

	// Google OAuth configuration.
	GoogleClientID     string // Env: GOOGLE_CLIENT_ID
	GoogleClientSecret string // Env: GOOGLE_CLIENT_SECRET
	GoogleRedirectURL  string // Env: GOOGLE_REDIRECT_URL
}

// LoadAuthConfig loads auth configuration from environment variables.
// It returns an error only if required fields are missing when auth is
// enabled (indicated by AILERON_DATABASE_URL being set).
func LoadAuthConfig() (*AuthConfig, error) {
	cfg := &AuthConfig{
		DatabaseURL:        os.Getenv("AILERON_DATABASE_URL"),
		JWTSigningKey:      os.Getenv("AILERON_JWT_SIGNING_KEY"),
		JWTIssuer:          envOrDefault("AILERON_JWT_ISSUER", "aileron"),
		UIRedirectURL:      envOrDefault("AILERON_UI_REDIRECT_URL", "/"),
		AutoVerifyEmail:    os.Getenv("AILERON_AUTO_VERIFY_EMAIL") == "true",
		GoogleClientID:     os.Getenv("GOOGLE_CLIENT_ID"),
		GoogleClientSecret: os.Getenv("GOOGLE_CLIENT_SECRET"),
		GoogleRedirectURL:  os.Getenv("GOOGLE_REDIRECT_URL"),
	}

	// Parse durations with defaults.
	var err error
	cfg.AccessTokenTTL, err = parseDurationOrDefault("AILERON_ACCESS_TOKEN_TTL", 15*time.Minute)
	if err != nil {
		return nil, err
	}
	cfg.RefreshTokenTTL, err = parseDurationOrDefault("AILERON_REFRESH_TOKEN_TTL", 7*24*time.Hour)
	if err != nil {
		return nil, err
	}

	// If no database URL is set, auth is disabled — return config as-is.
	if cfg.DatabaseURL == "" {
		return cfg, nil
	}

	// Validate required fields when auth is enabled.
	if cfg.JWTSigningKey == "" {
		return nil, fmt.Errorf("AILERON_JWT_SIGNING_KEY is required when AILERON_DATABASE_URL is set")
	}

	return cfg, nil
}

// AuthEnabled reports whether persistent auth is configured.
func (c *AuthConfig) AuthEnabled() bool {
	return c.DatabaseURL != ""
}

// GoogleEnabled reports whether Google OAuth is configured.
func (c *AuthConfig) GoogleEnabled() bool {
	return c.GoogleClientID != "" && c.GoogleClientSecret != ""
}

func envOrDefault(key, def string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return def
}

func parseDurationOrDefault(envKey string, def time.Duration) (time.Duration, error) {
	v := os.Getenv(envKey)
	if v == "" {
		return def, nil
	}
	d, err := time.ParseDuration(v)
	if err != nil {
		return 0, fmt.Errorf("invalid %s: %w", envKey, err)
	}
	return d, nil
}

// Package google implements the AuthProvider SPI for Google OAuth 2.0.
//
// It uses Google's OpenID Connect flow to authenticate users and retrieve
// their profile information (email, name, avatar). The provider is stateless;
// session management is handled by the caller.
package google

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"

	"github.com/ALRubinger/aileron/core/auth"
	"golang.org/x/oauth2"
	"golang.org/x/oauth2/google"
)

const userinfoURL = "https://www.googleapis.com/oauth2/v3/userinfo"

// Provider implements auth.AuthProvider for Google OAuth 2.0.
type Provider struct {
	clientID     string
	clientSecret string
	endpoint     oauth2.Endpoint
}

// New creates a Google OAuth provider with the given credentials.
// The redirect URL is supplied per-request via AuthorizationURL and HandleCallback,
// allowing it to be derived dynamically from the incoming request host.
func New(clientID, clientSecret string) *Provider {
	return &Provider{
		clientID:     clientID,
		clientSecret: clientSecret,
		endpoint:     google.Endpoint,
	}
}

// newConfig builds an oauth2.Config for a single request using the given redirectURL.
func (p *Provider) newConfig(redirectURL string) *oauth2.Config {
	return &oauth2.Config{
		ClientID:     p.clientID,
		ClientSecret: p.clientSecret,
		RedirectURL:  redirectURL,
		Endpoint:     p.endpoint,
		Scopes:       []string{"openid", "email", "profile"},
	}
}

// Provider returns "google".
func (p *Provider) Provider() string { return "google" }

// AuthorizationURL returns the Google OAuth consent URL.
// redirectURL must be the callback URL registered in the Google Cloud Console
// (or match the dynamic URL derived from the request host).
func (p *Provider) AuthorizationURL(_ context.Context, state, redirectURL string) (string, error) {
	url := p.newConfig(redirectURL).AuthCodeURL(state, oauth2.AccessTypeOffline)
	return url, nil
}

// HandleCallback exchanges the authorization code for user identity.
func (p *Provider) HandleCallback(ctx context.Context, req auth.CallbackRequest) (*auth.Identity, error) {
	cfg := p.newConfig(req.RedirectURL)
	token, err := cfg.Exchange(ctx, req.Code)
	if err != nil {
		return nil, fmt.Errorf("exchanging code: %w", err)
	}

	client := cfg.Client(ctx, token)
	resp, err := client.Get(userinfoURL)
	if err != nil {
		return nil, fmt.Errorf("fetching userinfo: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		body, _ := io.ReadAll(resp.Body)
		return nil, fmt.Errorf("userinfo returned %d: %s", resp.StatusCode, body)
	}

	var claims struct {
		Sub     string `json:"sub"`
		Email   string `json:"email"`
		Name    string `json:"name"`
		Picture string `json:"picture"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&claims); err != nil {
		return nil, fmt.Errorf("decoding userinfo: %w", err)
	}

	rawClaims := make(map[string]any)
	// Re-read is unnecessary; populate from typed fields.
	rawClaims["sub"] = claims.Sub
	rawClaims["email"] = claims.Email
	rawClaims["name"] = claims.Name
	rawClaims["picture"] = claims.Picture

	return &auth.Identity{
		Subject:     claims.Sub,
		Email:       claims.Email,
		DisplayName: claims.Name,
		AvatarURL:   claims.Picture,
		Provider:    "google",
		RawClaims:   rawClaims,
	}, nil
}

// RegisterRoutes registers auth routes on the given mux.
func (h *Handler) RegisterRoutes(mux *http.ServeMux) {
	mux.HandleFunc("GET /auth/{provider}/login", h.handleLogin)
	mux.HandleFunc("GET /auth/{provider}/callback", h.handleCallback)
	mux.HandleFunc("POST /auth/signup", h.handleSignup)
	mux.HandleFunc("POST /auth/verify-email", h.handleVerifyEmail)
	mux.HandleFunc("POST /auth/login", h.handleEmailLogin)
	mux.HandleFunc("POST /auth/refresh", h.handleRefresh)
	mux.HandleFunc("POST /auth/logout", h.handleLogout)
}

// handleLogin redirects to the provider's authorization URL.
func (h *Handler) handleLogin(w http.ResponseWriter, r *http.Request) {
	providerName := r.PathValue("provider")
	provider, ok := h.registry.Get(providerName)
	if !ok {
		http.Error(w, `{"error":"unknown auth provider"}`, http.StatusBadRequest)
		return
	}

	state, err := generateState()
	if err != nil {
		http.Error(w, `{"error":"internal error"}`, http.StatusInternalServerError)
		return
	}

	// Store state in a short-lived cookie for CSRF validation.
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		Path:     "/",
		MaxAge:   600, // 10 minutes
		HttpOnly: true,
		SameSite: http.SameSiteLaxMode,
		Secure:   r.TLS != nil,
	})

	url, err := provider.AuthorizationURL(r.Context(), state, h.callbackURL(r, providerName))
	if err != nil {
		h.log.Error("failed to generate auth URL", "error", err)
		http.Error(w, `{"error":"internal error"}`, http.StatusInternalServerError)
		return
	}

	http.Redirect(w, r, url, http.StatusTemporaryRedirect)
}

// callbackURL returns the OAuth callback URL for the given provider.
// If OAuthRedirectURL is configured it is returned as-is (useful for
// production deployments with a custom domain). Otherwise the URL is
// derived from the incoming request so that branch deployments (e.g. on
// Railway) work without any manual configuration.
func (h *Handler) callbackURL(r *http.Request, provider string) string {
	if h.oauthRedirectURL != "" {
		return h.oauthRedirectURL
	}
	scheme := "https"
	if r.TLS == nil && r.Header.Get("X-Forwarded-Proto") != "https" {
		scheme = "http"
	}
	host := r.Host
	if fwdHost := r.Header.Get("X-Forwarded-Host"); fwdHost != "" {
		host = fwdHost
	}
	return fmt.Sprintf("%s://%s/auth/%s/callback", scheme, host, provider)
}

// handleCallback processes the OAuth callback and creates a session.
func (h *Handler) handleCallback(w http.ResponseWriter, r *http.Request) {
	providerName := r.PathValue("provider")
	provider, ok := h.registry.Get(providerName)
