 13→// fakeProvider is a test AuthProvider that returns a fixed identity.
 14→type fakeProvider struct {
 15→	name     string
 16→	identity *Identity
 17→	err      error
 18→}
 19→
 20→func (f *fakeProvider) Provider() string { return f.name }
 21→
 22→func (f *fakeProvider) AuthorizationURL(_ context.Context, state, _ string) (string, error) {
 23→	return "https://fake-provider.example.com/auth?state=" + state, nil
 24→}
