 33→// newOAuthTestEnv creates a testEnv with a fake OAuth provider registered.
 34→func newOAuthTestEnv(identity *Identity) *testEnv {
 35→	te := newTestEnv()
 36→	te.handler.registry.Register(&fakeProvider{name: "fake", identity: identity})
 37→	return te
 38→}
