 51→		Subject:     "google-sub-123",
 52→		Email:       "alice@acme.com",
 53→		DisplayName: "Alice Smith",
 54→		AvatarURL:   "https://example.com/avatar.jpg",
 55→		Provider:    "fake",
 56→	})
 57→
 58→	w := te.doOAuthCallback("fake", "auth-code", "test-state")
 59→
 60→	// Should redirect (307) on success.
 61→	if w.Code != http.StatusTemporaryRedirect {
 62→		t.Fatalf("status = %d, want %d; body: %s", w.Code, http.StatusTemporaryRedirect, w.Body.String())
 63→	}
 64→
 65→	// User should be created.
 66→	user, err := te.users.GetByEmail(t.Context(), "alice@acme.com")
 67→	if err != nil {
 68→		t.Fatalf("user not found: %v", err)
 69→	}
