 71→		t.Errorf("display_name = %q, want Alice Smith", user.DisplayName)
 72→	}
 73→	if user.AuthProvider != "fake" {
 74→		t.Errorf("auth_provider = %q, want fake", user.AuthProvider)
 75→	}
 76→	if user.AuthProviderSubjectID != "google-sub-123" {
 77→		t.Errorf("subject = %q, want google-sub-123", user.AuthProviderSubjectID)
 78→	}
