143→func TestOAuthCallback_CrossProviderDedup(t *testing.T) {
144→	te := newTestEnv()
145→
146→	// Register provider_a.
147→	te.handler.registry.Register(&fakeProvider{
148→		name: "provider_a",
149→		identity: &Identity{
150→			Subject: "provider-a-sub", Email: "alice@acme.com",
151→			DisplayName: "Alice", Provider: "provider_a",
152→		},
153→	})
154→
155→	// First login via provider_a.
156→	r1 := httptest.NewRequest("GET", "/auth/provider_a/callback?code=c1&state=s1", nil)
157→	r1.AddCookie(&http.Cookie{Name: "oauth_state", Value: "s1"})
158→	w1 := httptest.NewRecorder()
159→	te.mux.ServeHTTP(w1, r1)
160→
161→	user1, _ := te.users.GetByEmail(t.Context(), "alice@acme.com")
162→
163→	// Register provider_b with same email but different subject.
164→	te.handler.registry.Register(&fakeProvider{
165→		name: "provider_b",
166→		identity: &Identity{
167→			Subject: "provider-b-sub", Email: "alice@acme.com",
168→			DisplayName: "Alice B", Provider: "provider_b",
169→		},
170→	})
171→
172→	// Second login via provider_b — should find same user by email.
173→	r2 := httptest.NewRequest("GET", "/auth/provider_b/callback?code=c2&state=s2", nil)
174→	r2.AddCookie(&http.Cookie{Name: "oauth_state", Value: "s2"})
175→	w2 := httptest.NewRecorder()
176→	te.mux.ServeHTTP(w2, r2)
177→
178→	if w2.Code != http.StatusTemporaryRedirect {
179→		t.Fatalf("status = %d, want 307; body: %s", w2.Code, w2.Body.String())
180→	}
181→
182→	// Should be the same user (deduplicated by email).
183→	user2, _ := te.users.GetByEmail(t.Context(), "alice@acme.com")
184→	if user2.ID != user1.ID {
185→		t.Errorf("expected same user ID across providers: %q != %q", user2.ID, user1.ID)
186→	}
187→}
