func TestProvider_AuthorizationURL(t *testing.T) {
	p := New("my-client-id", "my-secret")
	url, err := p.AuthorizationURL(context.Background(), "test-state-123", "https://example.com/callback")
	if err != nil {
		t.Fatalf("AuthorizationURL: %v", err)
	}
